import React from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useAuth } from '../context/AuthContext';
import Navbar from '../components/Navbar';
import SummaryCard from '../components/SummaryCard';

export default function Home() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <div className="min-h-screen bg-warmBg">
      <Navbar />

      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <motion.div
          className="flex flex-col sm:flex-row sm:items-center sm:justify-between mb-8"
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
        >
          <div>
            <h1 className="text-3xl sm:text-4xl font-bold" style={{ color: '#4A4A4A' }}>
              Welcome, {user?.name}! 👋
            </h1>
            <p className="text-gray-600 mt-2">
              Manage and optimize your subscriptions in one place
            </p>
          </div>

          <motion.button
            onClick={handleLogout}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            className="mt-4 sm:mt-0 px-6 py-3 text-white font-semibold rounded-lg transition-colors"
            style={{ backgroundColor: '#E8585C' }}
            onMouseEnter={(e) => e.target.style.backgroundColor = '#d43f46'}
            onMouseLeave={(e) => e.target.style.backgroundColor = '#E8585C'}
          >
            Logout
          </motion.button>
        </motion.div>

        {/* Dashboard Cards */}
        <motion.div
          className="grid grid-cols-1 md:grid-cols-3 gap-6"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ staggerChildren: 0.1 }}
        >
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
            <SummaryCard title="Total Spend" value="₹4,299" />
          </motion.div>
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
            <SummaryCard title="Zombies" value="5" />
          </motion.div>
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
            <SummaryCard title="Savings" value="₹1,890" />
          </motion.div>
        </motion.div>

        {/* User Info Card */}
        <motion.div
          className="mt-8 card-base"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.3 }}
        >
          <h2 className="text-xl font-bold text-textDark mb-4">Account Details</h2>
          <div className="space-y-3">
            <div className="flex justify-between items-center pb-3 border-b border-gray-200">
              <span className="text-gray-600">Name:</span>
              <span className="font-semibold text-textDark">{user?.name}</span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-gray-600">Email:</span>
              <span className="font-semibold text-textDark">{user?.email}</span>
            </div>
          </div>
        </motion.div>
      </div>
    </div>
  );
}
